    "slug": "the-secrets-of-black-holes-and-the-higgs-mass-could-be-hidden-in-a-7-dimensional-geometry",
    "cat": "Astrofísica",
    "catCls": "astrofisica",
    "img": "https://scx2.b-cdn.net/gfx/news/2026/the-secrets-of-black-h.jpg",
